import json, re

with open("chatgpt_extract/chat.html", "r") as f:
    html = f.read()

# The widget_state at 16567615 contains the report. Let's extract its full content.
# It's a JSON string (double-escaped)
start_pos = 16567616  # after the opening quote

text = []
i = start_pos
in_escape = False
count = 0
while i < len(html) and count < 500000:
    c = html[i]
    count += 1
    if in_escape:
        if c == 'n':
            text.append('\n')
        elif c == 't':
            text.append('\t')  
        elif c == '"':
            text.append('"')
        elif c == '\\':
            text.append('\\')
        elif c == 'u':
            hex_str = html[i+1:i+5]
            try:
                text.append(chr(int(hex_str, 16)))
            except:
                text.append(f'\\u{hex_str}')
            i += 4
        else:
            text.append(c)
        in_escape = False
        i += 1
        continue
    if c == '\\':
        in_escape = True
        i += 1
        continue
    if c == '"':
        break
    text.append(c)
    i += 1

widget_json_str = ''.join(text)
print(f"Widget state JSON length: {len(widget_json_str)} chars")

# Parse the inner JSON
try:
    ws = json.loads(widget_json_str)
    print(f"Parsed successfully. Keys: {list(ws.keys())}")

    # Look for report content
    def find_text_content(obj, path="", depth=0):
        if depth > 10:
            return
        if isinstance(obj, str):
            if len(obj) > 500 and ("CoStar" in obj or "Homes.com" in obj or "Matterport" in obj):
                print(f"\n=== TEXT at {path} (length {len(obj)}) ===")
                # Clean up
                clean = obj
                clean = re.sub(r'[\ue000-\ue2ff]+[^\s]*', '', clean)
                print(clean[:50000])
                if len(clean) > 50000:
                    print(f"\n[...TRUNCATED {len(clean)-50000} more chars...]")
        elif isinstance(obj, dict):
            for k, v in obj.items():
                find_text_content(v, f"{path}.{k}", depth+1)
        elif isinstance(obj, list):
            for idx, item in enumerate(obj):
                find_text_content(item, f"{path}[{idx}]", depth+1)

    find_text_content(ws)

except json.JSONDecodeError as e:
    print(f"JSON parse error: {e}")
    print(f"Content near error: {widget_json_str[max(0,e.pos-100):e.pos+100]}")

